# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib.request
import urllib.error
import base64


def lambda_handler(event, context):
    """
    Lambda@Edge Viewer Request function that enriches requests by fetching
    additional data from URLs specified in request headers.
    
    Reads URLs from X-Enrich-URL headers (comma-separated if multiple),
    fetches data from each URL, and attaches the results as additional
    headers before forwarding to origin.
    """
    request = event['Records'][0]['cf']['request']
    headers = request.get('headers', {})
    
    # Check for the X-Enrich-URL header
    enrich_header_key = 'x-enrich-url'
    
    if enrich_header_key not in headers:
        # No enrichment needed, pass through
        return request
    
    # Extract all enrichment URLs from the header(s)
    enrich_urls = []
    for header_entry in headers[enrich_header_key]:
        # Support comma-separated URLs in a single header value
        urls = [url.strip() for url in header_entry['value'].split(',')]
        enrich_urls.extend(urls)
    
    # Validate and filter URLs - only allow http/https
    valid_urls = []
    for url in enrich_urls:
        if url and (url.startswith('https://') or url.startswith('http://')):
            valid_urls.append(url)
    
    if not valid_urls:
        # Remove the enrich header and pass through
        _remove_header(headers, enrich_header_key)
        return request
    
    # Fetch data from each URL and collect results
    enrichment_results = []
    
    for idx, url in enumerate(valid_urls):
        result = _fetch_url(url)
        enrichment_results.append(result)
        
        # Add individual enrichment result headers
        # Header names must be lowercase for CloudFront
        result_header_key = f'x-enrichment-{idx}'
        
        # Base64 encode the result to safely pass in headers
        encoded_result = base64.b64encode(
            json.dumps(result).encode('utf-8')
        ).decode('utf-8')
        
        # Truncate if too long (CloudFront header value limit ~10KB)
        max_header_length = 8192
        if len(encoded_result) > max_header_length:
            # Truncate the data and mark as truncated
            result['truncated'] = True
            result['data'] = result.get('data', '')[:4096]
            encoded_result = base64.b64encode(
                json.dumps(result).encode('utf-8')
            ).decode('utf-8')
        
        headers[result_header_key] = [{'key': f'X-Enrichment-{idx}', 'value': encoded_result}]
    
    # Add a summary header with count of enrichments
    headers['x-enrichment-count'] = [{
        'key': 'X-Enrichment-Count',
        'value': str(len(enrichment_results))
    }]
    
    # Add enrichment status header
    successful = sum(1 for r in enrichment_results if r.get('status') == 'success')
    headers['x-enrichment-status'] = [{
        'key': 'X-Enrichment-Status',
        'value': f'{successful}/{len(enrichment_results)}'
    }]
    
    # Remove the original X-Enrich-URL header to avoid leaking internal config to origin
    _remove_header(headers, enrich_header_key)
    
    request['headers'] = headers
    return request


def _fetch_url(url, timeout=2):
    """
    Fetch data from a URL with timeout and error handling.
    
    Uses urllib (available in Lambda@Edge) instead of requests library
    since Lambda@Edge has a 1MB package limit and limited runtime.
    
    Args:
        url: The URL to fetch data from
        timeout: Request timeout in seconds (keep low for edge performance)
    
    Returns:
        dict with status, data, url, and optional error fields
    """
    result = {
        'url': url,
        'status': 'error',
        'data': None,
        'error': None,
        'status_code': None
    }
    
    try:
        req = urllib.request.Request(
            url,
            headers={
                'User-Agent': 'Lambda-Edge-Enrichment/1.0',
                'Accept': 'application/json, text/plain, */*',
            },
            method='GET'
        )
        
        with urllib.request.urlopen(req, timeout=timeout) as response:
            status_code = response.getcode()
            content_type = response.headers.get('Content-Type', '')
            raw_data = response.read().decode('utf-8', errors='replace')
            
            result['status_code'] = status_code
            
            # Try to parse as JSON
            if 'application/json' in content_type:
                try:
                    result['data'] = json.loads(raw_data)
                except json.JSONDecodeError:
                    result['data'] = raw_data
            else:
                result['data'] = raw_data
            
            result['status'] = 'success'
            
    except urllib.error.HTTPError as e:
        result['error'] = f'HTTP {e.code}: {e.reason}'
        result['status_code'] = e.code
    except urllib.error.URLError as e:
        result['error'] = f'URL Error: {str(e.reason)}'
    except TimeoutError:
        result['error'] = f'Timeout after {timeout}s'
    except Exception as e:
        result['error'] = f'Unexpected error: {str(e)}'
    
    return result


def _remove_header(headers, header_key):
    """
    Safely remove a header from the CloudFront headers dict.
    """
    lower_key = header_key.lower()
    if lower_key in headers:
        del headers[lower_key]